import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'Set Sample Data',
    parameters: {
      assignments: {
        assignments: [
          {
            id: 'field-message',
            name: 'message',
            value: 'hello',
            type: 'string'
          }
        ]
      }
    }
  }
});

export default workflow('manual-set-test', 'Manual Trigger - Set Node Test')
  .add(manualTrigger)
  .to(setNode);
